import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"无名剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/异仙劫/无名剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/异仙劫/无名剑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/异仙劫/无名剑.md"};function l(_,a,b,i,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"无名剑",tabindex:"-1"},[s("无名剑 "),e("a",{class:"header-anchor",href:"#无名剑","aria-label":'Permalink to "无名剑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序008")])])],-1),o('<h1 id="无名剑-1" tabindex="-1">无名剑 <a class="header-anchor" href="#无名剑-1" aria-label="Permalink to &quot;无名剑&quot;">​</a></h1><p>无名剑<br> D+500<br> 特异本质<br> 欧冶大师制作的一把长剑，薄如蝉翼，却以精妙的手法在灰白的剑身刻画了血色纹路，只有放在剑鞘中才能维持剑的存在。<br> 轻剑 6L 破甲1 体积3<br> &lt;此剑无名&gt;：过刚易折，天意如此。<br> 此剑平时放在配套的剑鞘，若将其取出，会在极短的时间内断裂，将其出鞘无需额外消耗动作。<br> 该武器仅能在出鞘后的短暂时间内用于进行一次白刃相关攻击检定，并且检定完毕后剑与剑鞘便会【无法避免】地自动碎裂，即使回到主神空间也无法恢复，并且此剑效果不可共享给其他武器。<br> 在攻击完毕后使用者获得不可减免的，等同于本次伤害数值的疲乏点数。<br> &lt;养剑&gt;：蛰伏数载，只为舍命一剑<br> 在购买此剑后，每当影片结束时，这把剑按以下顺序获得一项以下能力：<br> 1&gt;使用此剑进行攻击时获得等同于专业：剑等级的【高速】、【破甲】。<br> 2&gt;此剑的武器伤害提高等同于专业：剑的数值，使用此剑进行攻击时获得等同于专业：剑等级的器械加值。<br> 3&gt;使用此剑进行攻击时具有【法破】特性，并额外获得等同于 专业：剑/2（向下取整）的附加成功</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const g=r(d,[["render",l]]);export{f as __pageData,g as default};
